error_message:
{neo4j_code: Neo.ClientError.Statement.SyntaxError} {message: Invalid input 'PIVOT': expected ',', 'ORDER BY', 'CALL', 'CREATE', 'LOAD CSV', 'DELETE', 'DETACH', 'FINISH', 'FOREACH', 'INSERT', 'LIMIT', 'MATCH', 'MERGE', 'NODETACH', 'OFFSET', 'OPTIONAL', 'REMOVE', 'RETURN', 'SET', 'SKIP', 'UNION', 'UNWIND', 'USE', 'WHERE', 'WITH' or <EOF> (line 3, column 1 (offset: 102))
"PIVOT ("
 ^} {gql_status: 42001} {gql_status_description: error: syntax error or access rule violation - invalid syntax}

gt_cypher:
MATCH (s:Shape_Parameters)
WHERE NOT EXISTS {
  MATCH (s)<-[:HAS_SHAPE_PARAMETERS]-(i:ID)-[:HAS_STRESS_STATUS]->(st:Stress_Status)
  WHERE st.Status = 'large'
}
RETURN s.A_Area, s.S1_LongMajorAxis, s.S2_ShortMajorAxis LIMIT 5
